#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,X,Y;
        scanf("%lld %lld %lld %lld", &A, &B, &X, &Y);
        if (X*Y >= A*B) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

